<?php
namespace App\Modules\Hr\Performance\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Performance\Enums\PerformanceCycleStatus; use App\Modules\Hr\Performance\Models\HrPerformanceCycle;
class CreatePerformanceCycleAction { public function __construct(private HrAuditService $audit){} public function execute(array $data):HrPerformanceCycle{abort_unless(auth()->user()?->hasHrPermission('hr.performance.manage_templates'),403);$start=\Carbon\Carbon::parse($data['starts_on']??null);$end=\Carbon\Carbon::parse($data['ends_on']??null);$evalStart=\Carbon\Carbon::parse($data['evaluation_starts_on']??null);$evalEnd=\Carbon\Carbon::parse($data['evaluation_ends_on']??null);abort_if(blank($data['name']??null)||$end->lt($start)||$evalStart->lt($start)||$evalEnd->lt($evalStart),422,'Döngü tarihleri geçersiz.');$cycle=HrPerformanceCycle::create(['legal_entity_id'=>app(TenantContext::class)->getId(),'name'=>trim($data['name']),'starts_on'=>$start,'ends_on'=>$end,'evaluation_starts_on'=>$evalStart,'evaluation_ends_on'=>$evalEnd,'status'=>PerformanceCycleStatus::Draft,'created_by'=>auth()->id()]);$this->audit->log('performance_cycle_created',$cycle);return $cycle;} public function transition(HrPerformanceCycle $cycle,PerformanceCycleStatus $status):HrPerformanceCycle{abort_unless(auth()->user()?->hasHrPermission('hr.performance.manage_templates'),403);abort_unless($cycle->legal_entity_id===app(TenantContext::class)->getId(),404);$allowed=[PerformanceCycleStatus::Draft->value=>PerformanceCycleStatus::Active,PerformanceCycleStatus::Active->value=>PerformanceCycleStatus::Evaluation,PerformanceCycleStatus::Evaluation->value=>PerformanceCycleStatus::Calibration,PerformanceCycleStatus::Calibration->value=>PerformanceCycleStatus::Closed];abort_unless(($allowed[$cycle->status->value]??null)===$status,422,'Geçersiz döngü geçişi.');$from=$cycle->status;$cycle->update(['status'=>$status]);$this->audit->log('performance_cycle_transitioned',$cycle,['status'=>$from->value],['status'=>$status->value]);return $cycle->fresh();} }
